const uint8_t* font_xl_alpha_for(char c) {
    const uint8_t uc = static_cast<uint8_t>(c);
    if (uc < static_cast<uint8_t>(kFontFirstChar) ||
        uc > static_cast<uint8_t>(kFontLastChar)) {
        return kFallbackXLAlpha;
    }
    return kFontXLAlpha[uc - static_cast<uint8_t>(kFontFirstChar)];
}
